#include <bits/stdc++.h>
using namespace std;
const int N=1005,INF=0x3f3f3f3f;
vector<int> t[N];
int dp[N][5],n;
void dfs(int u)
{
    dp[u][4]=1,dp[u][1]=0,dp[u][0]=0;
    int len=t[u].size();
    for(int i=0;i<len;i++)
    {
        int v=t[u][i];
        dfs(v);
		dp[u][4]+=dp[v][0];
		dp[u][1]+=dp[v][2];
		dp[u][0]+=dp[v][1];
    }
    if(!len) dp[u][2]=dp[u][3]=1;
    else
    {
        dp[u][2]=dp[u][3]=INF;
        int cnt1=0,cnt2=0;
        for(int i=0;i<len;i++)
        {
            int v=t[u][i];
            cnt1+=dp[v][1];
            cnt2+=dp[v][2];
        }
        for(int i=0;i<len;i++)
        {
            int v=t[u][i];
            dp[u][3]=min(cnt1-dp[v][1]+dp[v][4],dp[u][3]);
            dp[u][2]=min(cnt2-dp[v][2]+dp[v][3],dp[u][2]);
        }

    }
    for(int i=3;i>-1;i--)
    {
        dp[u][i]=min(dp[u][i],dp[u][i+1]);
    }
}
int main()
{
    cin>>n;
    for(int i=2;i<=n;i++)
    {
        int u;
        cin>>u;
        t[u].push_back(i);
    }
    dfs(1);
    cout<<dp[1][2];
    return 0;
}
